import java.util.Arrays;

public class SelectionSort {

    public int[] sort(int[] arr) {
        int n = arr.length;
        for (int i = 0; i < n - 1; i++) {
            int minIdx = i;
            // TODO: find the index of the minimum element in arr[i+1..n-1]
            for (int j = i + 1; j < n; j++) {
                // TODO: if arr[j] < arr[minIdx], update minIdx = j
            }
            // Swap arr[i] with arr[minIdx]
            int temp = arr[i]; arr[i] = arr[minIdx]; arr[minIdx] = temp;
            System.out.println("Pass " + (i+1) + " (min idx=" + minIdx + "): " + Arrays.toString(arr));
        }
        return arr;
    }

    public static void main(String[] args) {
        SelectionSort ss = new SelectionSort();
        int[] arr = {64, 25, 12, 22, 11};
        System.out.println("Input:  " + Arrays.toString(arr));
        ss.sort(arr);
        System.out.println("Sorted: " + Arrays.toString(arr));
    }
}

